import java.io.*;
public class SerDemo {
    static class Point implements Serializable {
        int x, y;
        transient int cached;   // not serialized
        Point(int x, int y) { this.x = x; this.y = y; this.cached = x + y; }
    }

    public static void main(String[] args) throws Exception {
        Point p = new Point(3, 4);
        System.out.println(p.cached);

        // serialize
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        new ObjectOutputStream(bos).writeObject(p);

        // deserialize
        ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(bos.toByteArray()));
        Point q = (Point) ois.readObject();
        System.out.println(q.x + "," + q.y);
        System.out.println(q.cached);
    }
}
